function getSiteData() {
  try {
    const s = localStorage.getItem(SITE_DATA_KEY);
    if (s) {
      const d = JSON.parse(s);
      if (d && typeof d === 'object') {
        const merged = JSON.parse(JSON.stringify(DEFAULT_SITE));
        if (d.hero      && d.hero.headline)   merged.hero      = d.hero;
        if (d.services  && d.services.length) merged.services  = d.services;
        if (d.cases     && d.cases.length)    merged.cases     = d.cases;
        if (d.about     && d.about.name)      merged.about     = d.about;
        if (d.contact   && d.contact.email !== undefined) merged.contact = d.contact;
        if (d.logo)         merged.logo         = d.logo;
        if (d.whatsapp)     merged.whatsapp     = d.whatsapp;
        if (d.achievements && d.achievements.length) merged.achievements = d.achievements;
        if (d.typography)   merged.typography   = d.typography;
        if (d.theme_mode)   merged.theme_mode   = d.theme_mode;
        if (d.testimonials_visible !== undefined) merged.testimonials_visible = d.testimonials_visible;
        return merged;
      }
    }
  } catch(e) {}
  return JSON.parse(JSON.stringify(DEFAULT_SITE));
}

function setSiteData(data) {
  try {
    data._updated = new Date().toISOString();
    localStorage.setItem(SITE_DATA_KEY, JSON.stringify(data));
    return true;
  } catch(e) { return false; }
}

function injectPlaceholders(d) {
  const PH_HERO = 'https://images.unsplash.com/photo-1486325212027-8081e485255e?w=1600&q=80&fit=crop';
  const PH_CONS = 'https://images.unsplash.com/photo-1560250097-0b93528c311a?w=600&q=80&fit=crop';
  const PH_CASES = [
    'https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?w=900&q=80&fit=crop',
    'https://images.unsplash.com/photo-1545324418-cc1a3fa10c00?w=900&q=80&fit=crop',
    'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=900&q=80&fit=crop',
  ];
  const PH_SVCS = [
    'https://images.unsplash.com/photo-1504868584819-f8e8b4b6d7e3?w=800&q=80&fit=crop',
    'https://images.unsplash.com/photo-1600880292203-757bb62b4baf?w=800&q=80&fit=crop',
    'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=800&q=80&fit=crop',
    'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=800&q=80&fit=crop',
  ];
  if (!d.hero.image)  d.hero.image  = PH_HERO;
  if (!d.about.photo) d.about.photo = PH_CONS;
  (d.cases    || []).forEach((c,i) => { if (!c.image) c.image = PH_CASES[i % PH_CASES.length]; });
  (d.services || []).forEach((s,i) => { if (!s.image) s.image = PH_SVCS[i % PH_SVCS.length]; });
  return d;
}
